import type { ComponentPropsWithRef } from 'react';
import { SearchLg } from '@untitledui/icons';
import { cx } from '@/utils/cx';

import { EmptyState as BaseEmptyState } from '@/vendor/untitled-ui/application/empty-state/empty-state';

export type FeaturedIconProps = ComponentPropsWithRef<
  typeof BaseEmptyState.FeaturedIcon
>;

const FeaturedIcon = ({
  color = 'gray',
  theme = 'modern',
  icon = SearchLg,
  size = 'lg',
  ...props
}: FeaturedIconProps) => {
  return (
    <BaseEmptyState.FeaturedIcon
      {...props}
      {...{ color, theme, icon, size }}
    />
  );
};

export type IllustrationProps = ComponentPropsWithRef<
  typeof BaseEmptyState.Illustration
>;

const Illustration = ({
  type = 'cloud',
  color = 'gray',
  size = 'lg',
  ...props
}: IllustrationProps) => {
  return (
    <BaseEmptyState.Illustration
      {...props}
      {...{ type, color, size }}
      className={cx('z-10', props.className)}
    />
  );
};

export type FileTypeIconProps = ComponentPropsWithRef<
  typeof BaseEmptyState.FileTypeIcon
>;

const FileTypeIcon = ({
  type = 'folder',
  theme = 'solid',
  ...props
}: FileTypeIconProps) => {
  return (
    <BaseEmptyState.FileTypeIcon
      {...props}
      {...{ type, theme }}
    ></BaseEmptyState.FileTypeIcon>
  );
};

export type HeaderProps = ComponentPropsWithRef<typeof BaseEmptyState.Header>;

const Header = ({
  pattern = 'circle',
  patternSize = 'md',
  ...props
}: HeaderProps) => {
  return (
    <BaseEmptyState.Header
      {...props}
      {...{ patternSize, pattern }}
      className={cx('text-gray-200', props.className)}
    >
      {props.children}
    </BaseEmptyState.Header>
  );
};

export type ContentProps = ComponentPropsWithRef<typeof BaseEmptyState.Content>;
const Content = (props: ContentProps) => {
  return (
    <BaseEmptyState.Content {...props}>{props.children}</BaseEmptyState.Content>
  );
};

export type FooterProps = ComponentPropsWithRef<typeof BaseEmptyState.Footer>;
const Footer = (props: FooterProps) => {
  return (
    <BaseEmptyState.Footer {...props}>{props.children}</BaseEmptyState.Footer>
  );
};

export type TitleProps = ComponentPropsWithRef<typeof BaseEmptyState.Title>;
const Title = (props: TitleProps) => {
  return (
    <BaseEmptyState.Title {...props}>{props.children}</BaseEmptyState.Title>
  );
};

export type DescriptionProps = ComponentPropsWithRef<
  typeof BaseEmptyState.Description
>;
const Description = (props: DescriptionProps) => {
  return (
    <BaseEmptyState.Description {...props}>
      {props.children}
    </BaseEmptyState.Description>
  );
};

const Root = (
  props: Omit<
    ComponentPropsWithRef<typeof BaseEmptyState>,
    | 'Title'
    | 'Header'
    | 'Footer'
    | 'Content'
    | 'Description'
    | 'Illustration'
    | 'FeaturedIcon'
    | 'FileTypeIcon'
  >,
) => {
  return (
    <div className="py-32">
      <BaseEmptyState {...props}>{props.children}</BaseEmptyState>
    </div>
  );
};

const EmptyState = Root as typeof Root & {
  Title: typeof Title;
  Header: typeof Header;
  Footer: typeof Footer;
  Content: typeof Content;
  Description: typeof Description;
  Illustration: typeof Illustration;
  FeaturedIcon: typeof FeaturedIcon;
  FileTypeIcon: typeof FileTypeIcon;
};

EmptyState.Title = Title;
EmptyState.Header = Header;
EmptyState.Footer = Footer;
EmptyState.Content = Content;
EmptyState.Description = Description;
EmptyState.Illustration = Illustration;
EmptyState.FeaturedIcon = FeaturedIcon;
EmptyState.FileTypeIcon = FileTypeIcon;

export { EmptyState };
